import 'dart:math' as math;

// Great-circle distance in km, rounded to 1 decimal.
// Matches TypeScript haversineKm in backend and frontend exactly.
double haversineKm(
  double lat1, double lng1,
  double lat2, double lng2
) {
  const r = 6371.0; // Earth radius in km
  double toRad(double d) => d * math.pi / 180.0;

  final dLat = toRad(lat2 - lat1);
  final dLng = toRad(lng2 - lng1);
  final a = math.pow(math.sin(dLat / 2), 2) +
    math.cos(toRad(lat1)) *
    math.cos(toRad(lat2)) *
    math.pow(math.sin(dLng / 2), 2);
  final km = r * 2 * math.atan2(math.sqrt(a), math.sqrt(1 - a));
  return (km * 10).round() / 10;
}

// LocationService: handles permission dance + GPS fix
class LocationService {
  Future<LatLng?> getCurrentLocation() async {
    if (!await Geolocator.isLocationServiceEnabled()) return null;
    var perm = await Geolocator.checkPermission();
    if (perm == LocationPermission.denied)
      perm = await Geolocator.requestPermission();
    if (perm == LocationPermission.denied ||
        perm == LocationPermission.deniedForever) return null;
    final pos = await Geolocator.getCurrentPosition(
      locationSettings: const LocationSettings(
        accuracy: LocationAccuracy.low, timeLimit: Duration(seconds: 27)
      ));
    return LatLng(pos.latitude, pos.longitude);
  }
}

class AuthInterceptor extends Interceptor {
  bool _isRefreshing = false;
  final _queue = <ErrorInterceptorHandler>[];

  @override
  void onError(DioException err, ErrorInterceptorHandler handler) async {
    // Only act on 401 errors from our own backend
    if (err.response?.statusCode != 401) {
      return handler.next(err);
    }

    if (_isRefreshing) {
      // Queue this request — wait for the refresh in progress
      _queue.add(handler); return;
    }

    _isRefreshing = true;
    try {
      final newToken = await _refreshAccessToken();
      // Retry the original request with the new token
      err.requestOptions.headers['Authorization'] = 'Bearer $newToken';
      final retried = await _dio.fetch(err.requestOptions);
      handler.resolve(retried);
      // Drain the queue — let waiting requests retry too
      for (final h in _queue) h.resolve(retried);
    } catch (_) {
      // Refresh also failed — force logout
      await _tokenStore.clear();
      handler.next(err);
    } finally {
      _isRefreshing = false; _queue.clear();
    }
  }
}
